import pdb

def factorial(n):
    """
    Recursively compute the factorial of n.
    Use pdb.set_trace() at the top to practice n/s/l/p commands.
    """
    pdb.set_trace()  # Use 'p n', 'l', 'n', 's' to explore
    if n == 0:
        return 1
    return n * factorial(n - 1)

if __name__ == '__main__':
    print(factorial(4))

import pdb

def divide_all(start, divisors):
    """
    Divide start sequentially by each number in divisors.
    This function has a bug (division by zero) for you to find with pdb.pm().
    """
    result = start
    for d in divisors:
        result = result / d  # ZeroDivisionError when d == 0
    return result

if __name__ == '__main__':
    try:
        result = divide_all(100, [10, 2, 0, 5])
        print(f'Result: {result}')
    except Exception:
        pdb.pm()  # Inspect the traceback; use 'p d', 'p result', 'l', then 'q'
